import{_ as i,o as t,c as o,ai as e}from"./chunks/framework.ampVZV4B.js";const d=JSON.parse('{"title":"数据库面试总览：高频 8 题（初/中级必备）","description":"","frontmatter":{},"headers":[],"relativePath":"database/overview.md","filePath":"database/overview.md"}'),r={name:"database/overview.md"};function a(s,l,n,p,c,g){return t(),o("div",null,[...l[0]||(l[0]=[e('<h1 id="数据库面试总览-高频-8-题-初-中级必备" tabindex="-1">数据库面试总览：高频 8 题（初/中级必备） <a class="header-anchor" href="#数据库面试总览-高频-8-题-初-中级必备" aria-label="Permalink to “数据库面试总览：高频 8 题（初/中级必备）”">​</a></h1><blockquote><p>这不是一份“从零讲数据库”的教程，而是专门帮我<strong>应对面试</strong>用的提纲：<br> 把常问的数据库面试题集中列出来，细节放在后面的专题文章里慢慢啃。</p></blockquote><hr><h2 id="一、数据库高频面试题总表" tabindex="-1">一、数据库高频面试题总表 <a class="header-anchor" href="#一、数据库高频面试题总表" aria-label="Permalink to “一、数据库高频面试题总表”">​</a></h2><p>下面这 8 道题，是初/中级开发几乎绕不开的数据库面试题，可以当作我的<strong>必背清单</strong>：</p><ol><li><p><strong>MySQL 索引用的是什么数据结构？为什么不用红黑树？</strong></p><ul><li>关键点：B+ 树、多叉树、磁盘 IO 次数少、范围查询友好</li><li>延伸：<strong>聚集索引 vs 非聚集索引（InnoDB vs MyISAM）</strong></li><li>👉 详细见：<a href="./mysql-index.html">MySQL 索引与 B+ 树原理</a></li></ul></li><li><p><strong>哪些情况会导致索引失效？</strong></p></li><li><p><strong>哪些情况会导致索引失效？</strong></p><ul><li>关键点：<code>LIKE &#39;%xxx&#39;</code>、对索引列做函数/运算、类型不一致导致隐式转换、在 <code>OR</code> 中混入非索引列</li><li>延伸：覆盖索引、最左前缀原则、联合索引设计</li><li>👉 详细见：<a href="./sql-optimization.html">SQL 优化与索引使用姿势</a></li></ul></li><li><p><strong>怎么分析慢查询？你平时会怎么排查？</strong></p><ul><li>关键点：<code>EXPLAIN</code> 看执行计划，关注 <code>type / key / rows / extra</code></li><li>延伸：慢查询日志、加索引前先看“是不是业务写法有问题”</li><li>👉 详细见：<a href="./slow-query-scenario.html">慢查询场景与排查思路</a></li></ul></li><li><p><strong>MySQL 事务的 ACID 是什么？具体怎么实现的？</strong></p><ul><li>关键点：原子性（undo log）、持久性（redo log）、隔离性（锁 + MVCC）、一致性（约束 + 业务逻辑）</li><li>延伸：redo / undo 的区别、崩溃恢复大致流程</li><li>👉 详细见：<a href="./mysql-transaction-lock.html">MySQL 事务与锁的核心原理</a></li></ul></li><li><p><strong>MySQL 有哪几种隔离级别？会带来哪些并发现象？</strong></p><ul><li>关键点： <ul><li>READ UNCOMMITTED：可能脏读</li><li>READ COMMITTED：解决脏读，可能不可重复读</li><li>REPEATABLE READ（InnoDB 默认）：解决不可重复读，靠 MVCC 处理大部分幻读</li><li>SERIALIZABLE：串行化，完全隔离，性能最差</li></ul></li><li>延伸：快照读 vs 当前读、间隙锁 / Next-Key Lock</li><li>👉 详细见：<a href="./mysql-transaction-lock.html">MySQL 事务与锁的核心原理</a></li></ul></li><li><p><strong>什么是 SQL 注入？怎么防护？</strong></p><ul><li>关键点：字符串拼接 SQL 被恶意拼入条件或语句</li><li>防护：参数化查询、预编译、使用 MyBatis/JPA 等 ORM、对外暴露接口不要直接透传拼接条件</li><li>👉 可结合项目中登录/查询接口，自行准备 1～2 个简单案例</li></ul></li><li><p><strong>为什么要用数据库连接池？HikariCP 有什么优势？</strong></p><ul><li>关键点：数据库连接建立成本高，通过连接池<strong>复用连接</strong>、限制并发连接数，防止数据库被打挂</li><li>HikariCP 优势：轻量、性能好、配置简单，Spring Boot 默认推荐</li><li>👉 详细见：<a href="./connection-pool.html">数据库连接池与 HikariCP</a></li></ul></li><li><p><strong>主键和唯一索引有什么区别？</strong></p><ul><li>关键点： <ul><li>主键：不允许为 NULL，一张表只能有一个主键（可以是联合主键）</li><li>唯一索引：允许有一个 NULL，可以有多个唯一索引</li></ul></li><li>延伸：自增主键 vs 业务主键（UUID、订单号等）的优缺点</li><li>👉 可以结合自己项目，想清楚“为什么这样设计主键”</li></ul></li></ol><p>建议在复习数据库模块前，先把这 8 道题自己写一份<strong>“标准回答 + 延伸追问”</strong>，形成自己的话术。</p><blockquote><p>说明：我这里不强调“纸上手写 SQL”。更多是面试中常见的形式：给你一个需求，你能不能<strong>快速写出/口述出正确 SQL</strong>，并解释为什么这么写、可能用到哪些索引。</p></blockquote><hr><h2 id="二、如何使用这个数据库面试模块" tabindex="-1">二、如何使用这个数据库面试模块 <a class="header-anchor" href="#二、如何使用这个数据库面试模块" aria-label="Permalink to “二、如何使用这个数据库面试模块”">​</a></h2><ul><li><p><strong>第一步：从这 8 题开始</strong><br> 先保证：每一道题你都能<strong>用自己的话讲 2～3 分钟</strong>，而不是背概念。</p></li><li><p><strong>第二步：对照专题文章补齐细节</strong><br> 遇到没讲顺的地方，就去看对应的文章：</p><ul><li>索引原理与最左前缀 → <a href="/my-vitepress-site/database/mysql-index.html">MySQL 索引底层原理</a></li><li>慢查询与执行计划 → <a href="/my-vitepress-site/database/slow-query-scenario.html">场景实战：慢查询排查</a>、<a href="/my-vitepress-site/database/sql-optimization.html">SQL 优化与执行计划</a></li><li>事务、隔离级别、锁 → <a href="/my-vitepress-site/database/mysql-transaction-lock.html">MySQL 事务与锁机制</a></li><li>连接池原理 → <a href="/my-vitepress-site/database/connection-pool.html">数据库连接池调优</a></li></ul></li><li><p><strong>第三步：准备 1～2 个与数据库相关的项目案例</strong><br> 比如：</p><ul><li>“我们系统里有一个订单表，最开始没建合适的索引，导致某个查询特别慢，后来我是怎么定位和优化的……”</li><li>“因为并发写多了之后出现了死锁，我是怎么查到死锁信息，并通过调整 SQL 顺序/拆分事务解决的……”</li></ul></li></ul><p>面试的时候，只要围绕这 8 道题 + 自己的项目经历展开，大部分初/中级数据库相关的问答都能比较从容地应对。</p><hr><blockquote><p>🔁 小结：</p><ul><li>这篇是<strong>总览 +题单</strong>，适合临上战场前快速过一遍。</li><li>细节、原理、图示和更多延伸问题，放在后面的数据库专题文章里慢慢消化即可。</li></ul></blockquote>',14)])])}const h=i(r,[["render",a]]);export{d as __pageData,h as default};
